"""Public async surface for the Cursor SDK.

Mirrors the sync API exposed at the top of the `cursor_sdk` package, but
backed by `httpx.AsyncClient` and `asyncio` subprocess management.

Typical usage::

    import asyncio
    from cursor_sdk.asyncio import AsyncAgent, AsyncCursor, AsyncClient

    async def main() -> None:
        async with await AsyncClient.launch_bridge(workspace=".") as client:
            me = await AsyncCursor.me(client=client, api_key="...")
            agent = await AsyncAgent.create(
                client=client,
                api_key="...",
                model={"id": "composer-2"},
            )
            run = await agent.send("Hello!")
            async for event in run:
                print(event.kind)
            result = await run.wait()
            print(result.status)

    asyncio.run(main())

Design notes:
    - Sync (`Client`, `Agent`, `Run`, `Cursor`) and async (`AsyncClient`,
      `AsyncAgent`, `AsyncRun`, `AsyncCursor`) clients should NOT be mixed in
      the same code path; share a `BridgeEndpoint` instead.
    - There is no global async default client. Instantiate `AsyncClient`
      explicitly (or use `AsyncClient.launch_bridge(...)`) to avoid
      cross-event-loop bugs from sharing a global handle.
"""

from __future__ import annotations

from ._async_agent import AsyncAgent
from ._async_bridge import AsyncBridge
from ._async_client import AsyncClient, AsyncCursorClient
from ._async_connect import AsyncConnectTransport, DefaultAsyncHttpxClient
from ._async_cursor import AsyncCursor
from ._async_run import AsyncRun

